scwin.onpageload = function () {
  const codeOptions = [{
    grpCd: "JA010",
    compID: "acb_cond_bizTypCd,acb_bizTypCd"
  }, {
    grpCd: "JA060",
    compID: "acb_eqNrmCd,gr_results:ton"
  }, {
    grpCd: "JA080",
    compID: "acb_trfAdptCd"
  }, {
    grpCd: "JA090",
    compID: "acb_degClsCd"
  }];
  $c.data.setCommonCode($p, codeOptions, scwin.setCommonCodeCallBack);
};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
  $p.setTimeout(function () {
    $c.gus.cfDisableObjects($p, [ed_prdyr, ed_vehclNo, ed_drcrNo, ed_degNm, ed_degForm, acb_eqNrmCd, ed_stdFleffcncy, ed_clntNo_rslts, ed_clntNm_rslts, acb_bizTypCd, acb_trfAdptCd, ed_outBranch, ica_inspDt1, ica_inspDt2, acb_degClsCd, ica_degDt, ica_firstRegDt, ica_chkDt, rd_useYn, ed_rmk]);
  }, {
    "delay": 50
  });
};
scwin.setCommonCodeCallBack = function () {
  acb_cond_bizTypCd.addItem("전체", "", "", 0);
  acb_cond_bizTypCd.setSelectedIndex(0);
  acb_bizTypCd.addItem("전체", "", "", 0);
  acb_bizTypCd.setSelectedIndex(0);
};

//-------------------------------------------------------------------------
// function name : scwin.f_Retrieve
// function desc : 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = function () {
  ds_results.removeAll();
  ds_incidentalExpenses.removeAll();
  $c.sbm.execute($p, sbm_retrieve);
};
scwin.f_Retrieve_incExpense = function () {
  ds_cond_incidentalExpenses.set("eqCd", ds_results.getCellData(ds_results.getRowPosition(), "eqCd"));
  $c.sbm.execute($p, sbm_retrieve_incExpense);
};

//-------------------------------------------------------------------------
// function name : scwin.f_Save
// function desc : 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
  for (var i = 0; i < ds_incidentalExpenses.getRowCount(); i++) {
    if (ds_incidentalExpenses.getRowStatus(i) == "C" || ds_incidentalExpenses.getRowStatus(i) == "D" || ds_incidentalExpenses.getRowStatus(i) == "U") {
      if (ds_incidentalExpenses.getCellData(i, "adptYm") == "" && ds_incidentalExpenses.getCellData(i, "adptStDt") == "") {
        await $c.win.alert($p, i + 1 + "번재 행의 적용년월 또는 적용기간은 필수 입력 항목 입니다.");
        return false;
      }
      if (ds_incidentalExpenses.getCellData(i, "adptYm") == "" && (ds_incidentalExpenses.getCellData(i, "adptStDt") == "" || ds_incidentalExpenses.getCellData(i, "adptEndDt") == "")) {
        await $c.win.alert($p, i + 1 + "번재 행의  적용기간의 FROM,TO는  필수 입력 항목 입니다.");
        return false;
      }
      if (ds_incidentalExpenses.getCellData(i, "clntNo") == "") {
        await $c.win.alert($p, i + 1 + "번째 행의 거래처 정보를 등록해 주십시오.");
        return false;
      }
      if (ds_incidentalExpenses.getCellData(i, "selpchItemCd") == "") {
        await $c.win.alert($p, i + 1 + "번째 행의 청구/정산 정보를 등록해 주십시오.");
        return false;
      }
      if (ds_incidentalExpenses.getCellData(i, "amtWcrc") == "") {
        await $c.win.alert($p, i + 1 + "번째 행의 금액을 등록해 주십시오.");
        return false;
      }
      if (ds_incidentalExpenses.getCellData(i, "deductYn") == 1) {
        if (ds_incidentalExpenses.getCellData(i, "adptDeg") == "") {
          await $c.win.alert($p, i + 1 + "번째 행의 적용차수을 등록해 주십시오.");
          return false;
        }
        if (ds_incidentalExpenses.getCellData(i, "allDeg") == "") {
          await $c.win.alert($p, i + 1 + "번째 행의 전체차수을 등록해 주십시오.");
          return false;
        }
        if (ds_incidentalExpenses.getCellData(i, "adptTerm") == "") {
          await $c.win.alert($p, i + 1 + "번째 행의 적용기간을 등록해 주십시오.");
          return false;
        }
      }
    }
  }
  if (await $c.win.confirm($p, MSG_CM_CRM_001)) {
    //저장하시겠습니까?
    $c.sbm.execute($p, sbm_save);
  }
};

